// Helper to build a tracking history for received POs
const buildReceivedTracking = (orderDate: string, expectedDate: string, receivedDate: string): TrackingEvent[] => [
  { id: 'T1', timestamp: `${orderDate} 10:00`, status: 'Ordered', location: 'Vendor Warehouse', description: 'Purchase order placed and confirmed by vendor', user: 'Admin' },
  { id: 'T2', timestamp: `${orderDate} 18:30`, status: 'Processing', location: 'Vendor Warehouse', description: 'Order is being prepared for shipment', user: 'Vendor' },
  { id: 'T3', timestamp: `${expectedDate} 09:00`, status: 'In Transit', location: 'In Transit', description: 'Shipment dispatched and in transit to warehouse', user: 'Logistics' },
  { id: 'T4', timestamp: `${receivedDate} 14:00`, status: 'Received', location: 'Destination Warehouse', description: 'Shipment received and verified at warehouse', user: 'Receiving Team' },
];

const buildInTransitTracking = (orderDate: string): TrackingEvent[] => [
  { id: 'T1', timestamp: `${orderDate} 10:00`, status: 'Ordered', location: 'Vendor Warehouse', description: 'Purchase order placed and confirmed', user: 'Admin' },
  { id: 'T2', timestamp: `${orderDate} 16:00`, status: 'Processing', location: 'Vendor Warehouse', description: 'Order being prepared for shipment', user: 'Vendor' },
  { id: 'T3', timestamp: `${orderDate} 20:00`, status: 'In Transit', location: 'Highway NH-48', description: 'Shipment in transit. Expected delivery within 2-3 days.', user: 'Logistics' },
];

const buildOrderedTracking = (orderDate: string): TrackingEvent[] => [
  { id: 'T1', timestamp: `${orderDate} 11:00`, status: 'Ordered', location: 'Vendor Warehouse', description: 'Purchase order placed. Awaiting vendor confirmation.', user: 'Admin' },
];

