// Helper to compute P&L per warehouse per month
function makePL(period: string, fy: string, warehouseId: string, warehouseName: string, revenue: number, cogsRate: number, expired = 0, damaged = 0, returns = 0): ProfitLossData {
  const cogs = Math.round(revenue * cogsRate);
  const grossProfit = revenue - cogs;
  const totalLoss = expired + damaged + returns;
  const netProfit = grossProfit - totalLoss;
  const margin = revenue > 0 ? Number(((netProfit / revenue) * 100).toFixed(1)) : 0;
  return { period, fy, warehouseId, warehouseName, revenue, cogs, grossProfit, expiredLoss: expired, damagedLoss: damaged, returnsLoss: returns, totalLoss, netProfit, margin };
}

